import {
  createContext,
  forwardRef,
  type HTMLAttributes,
  type ReactNode,
  useCallback,
  useContext,
  useMemo,
  useRef,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';

export type MenuMode = 'vertical' | 'horizontal';

export interface MenuContextValue {
  /** Layout mode. */
  mode: MenuMode;
  /** Currently active item index. */
  activeIndex: string;
  /** Mark an item as active (no-op when its index already matches). */
  setActive: (index: string) => void;
  /** Indices of the currently expanded sub-menus. */
  openedMenus: string[];
  /** Expand or collapse a sub-menu by index. */
  toggleMenu: (index: string) => void;
  /** Open a sub-menu by index (no-op when already open). */
  openMenu: (index: string) => void;
  /** Collapse a sub-menu by index (no-op when already closed). */
  closeMenu: (index: string) => void;
  /** Collapse a sub-menu and its whole ancestor chain (used when selecting an item). */
  closeMenuBranch: (index: string) => void;
  /** Register a sub-menu and its parent sub-menu (if any) for ancestor tracking. */
  registerSubMenu: (index: string, parentIndex: string | null) => void;
  /** Remove a sub-menu registration. */
  unregisterSubMenu: (index: string) => void;
  /** Collapse vertical menus to icons only. */
  collapse: boolean;
  /** Allow only one sub-menu open at a time. */
  uniqueOpened: boolean;
}

/** Sub-menu context carrying the current sub-menu index to its descendants. */
export interface SubMenuContextValue {
  /** Index of the nearest enclosing sub-menu, used as the parent path. */
  parentIndex: string;
}

export const SubMenuContext = createContext<SubMenuContextValue | null>(null);

/** Access the nearest enclosing SubMenu context. Returns `null` at the top level. */
export function useSubMenuContext(): SubMenuContextValue | null {
  return useContext(SubMenuContext);
}

export const MenuContext = createContext<MenuContextValue | null>(null);

/** Access the nearest Menu context. Returns `null` when rendered outside a Menu. */
export function useMenuContext(): MenuContextValue | null {
  return useContext(MenuContext);
}

export interface MenuProps extends Omit<HTMLAttributes<HTMLUListElement>, 'onChange' | 'onSelect'> {
  /** Layout mode. */
  mode?: MenuMode;
  /** Active item index (controlled). */
  value?: string;
  /** Initial active item index (uncontrolled). */
  defaultActive?: string;
  /** Fired when the active index changes. */
  onChange?: (index: string) => void;
  /** Collapse to icons only. Vertical mode only. */
  collapse?: boolean;
  /** Sub-menu indices opened by default. */
  defaultOpeneds?: string[];
  /** Keep only one sub-menu open at a time. */
  uniqueOpened?: boolean;
  /** Fired when an item is selected. */
  onSelect?: (index: string) => void;
  /** Fired when a sub-menu expands. */
  onOpen?: (index: string) => void;
  /** Fired when a sub-menu collapses. */
  onClose?: (index: string) => void;
  children?: ReactNode;
}

export const Menu = forwardRef<HTMLUListElement, MenuProps>(function Menu(props, ref) {
  const {
    mode = 'vertical',
    value,
    defaultActive,
    onChange,
    collapse = false,
    defaultOpeneds,
    uniqueOpened = false,
    onSelect,
    onOpen,
    onClose,
    className,
    children,
    ...rest
  } = props;

  const ns = useNamespace('menu');

  const isControlled = value !== undefined;
  const [internalActive, setInternalActive] = useState<string>(defaultActive ?? '');
  const activeIndex = isControlled ? value : internalActive;

  const [openedMenus, setOpenedMenus] = useState<string[]>(defaultOpeneds ?? []);

  // Maps each sub-menu index to its parent sub-menu index (or null at the top level).
  // Used to preserve the ancestor chain when `uniqueOpened` closes sibling branches.
  const parentMapRef = useRef<Map<string, string | null>>(new Map());

  const registerSubMenu = useCallback((index: string, parentIndex: string | null) => {
    parentMapRef.current.set(index, parentIndex);
  }, []);

  const unregisterSubMenu = useCallback((index: string) => {
    parentMapRef.current.delete(index);
  }, []);

  /** Collect the ancestor chain (parents, grandparents, ...) of a sub-menu index. */
  const collectAncestors = useCallback((index: string): string[] => {
    const ancestors: string[] = [];
    let current = parentMapRef.current.get(index) ?? null;
    while (current) {
      ancestors.push(current);
      current = parentMapRef.current.get(current) ?? null;
    }
    return ancestors;
  }, []);

  const setActive = useCallback(
    (index: string) => {
      if (!isControlled) {
        setInternalActive(index);
      }
      onSelect?.(index);
      if (index !== activeIndex) {
        onChange?.(index);
      }
    },
    [isControlled, onSelect, onChange, activeIndex],
  );

  const openMenu = useCallback(
    (index: string) => {
      setOpenedMenus((prev) => {
        if (prev.includes(index)) {
          return prev;
        }
        onOpen?.(index);
        if (!uniqueOpened) {
          return [...prev, index];
        }
        // With uniqueOpened, close sibling branches but keep this index's
        // ancestor chain open so nested sub-menus stay reachable.
        const keep = new Set([index, ...collectAncestors(index)]);
        return [...prev.filter((item) => keep.has(item)), index];
      });
    },
    [onOpen, uniqueOpened, collectAncestors],
  );

  const closeMenu = useCallback(
    (index: string) => {
      setOpenedMenus((prev) => {
        if (!prev.includes(index)) {
          return prev;
        }
        onClose?.(index);
        return prev.filter((item) => item !== index);
      });
    },
    [onClose],
  );

  const closeMenuBranch = useCallback(
    (index: string) => {
      const branch = new Set([index, ...collectAncestors(index)]);
      setOpenedMenus((prev) => {
        const next = prev.filter((item) => !branch.has(item));
        if (next.length === prev.length) {
          return prev;
        }
        for (const item of prev) {
          if (branch.has(item)) {
            onClose?.(item);
          }
        }
        return next;
      });
    },
    [collectAncestors, onClose],
  );

  const toggleMenu = useCallback(
    (index: string) => {
      if (openedMenus.includes(index)) {
        closeMenu(index);
      } else {
        openMenu(index);
      }
    },
    [openedMenus, openMenu, closeMenu],
  );

  const collapsed = mode === 'vertical' && collapse;

  const context = useMemo<MenuContextValue>(
    () => ({
      mode,
      activeIndex,
      setActive,
      openedMenus,
      toggleMenu,
      openMenu,
      closeMenu,
      closeMenuBranch,
      registerSubMenu,
      unregisterSubMenu,
      collapse: collapsed,
      uniqueOpened,
    }),
    [
      mode,
      activeIndex,
      setActive,
      openedMenus,
      toggleMenu,
      openMenu,
      closeMenu,
      closeMenuBranch,
      registerSubMenu,
      unregisterSubMenu,
      collapsed,
      uniqueOpened,
    ],
  );

  const classes = cls(
    ns.b(),
    ns.m(mode),
    ns.is('collapse', collapsed),
    className,
  );

  return (
    <MenuContext.Provider value={context}>
      <ul
        ref={ref}
        className={classes}
        role="menu"
        aria-orientation={mode === 'horizontal' ? 'horizontal' : 'vertical'}
        {...rest}
      >
        {children}
      </ul>
    </MenuContext.Provider>
  );
});

import { forwardRef, type LiHTMLAttributes, type ReactNode } from 'react';
import { cls, useNamespace } from '../../utils';
import { useMenuContext, useSubMenuContext } from './Menu';

export interface MenuItemProps extends Omit<LiHTMLAttributes<HTMLLIElement>, 'onClick'> {
  /** Unique identifier used to mark the item active. */
  index: string;
  /** Disable interaction. */
  disabled?: boolean;
  /** Leading icon. */
  icon?: ReactNode;
  children?: ReactNode;
}

export const MenuItem = forwardRef<HTMLLIElement, MenuItemProps>(function MenuItem(props, ref) {
  const { index, disabled = false, icon, className, style, children, ...rest } = props;

  const ns = useNamespace('menu-item');
  const menu = useMenuContext();
  const parent = useSubMenuContext();

  const isActive = menu?.activeIndex === index;

  const handleClick = () => {
    if (disabled) {
      return;
    }
    menu?.setActive(index);
    // Selecting an item inside a horizontal popup collapses the open sub-menu
    // chain, mirroring Element Plus. Inline (vertical) sub-menus stay expanded.
    if (menu?.mode === 'horizontal' && parent) {
      menu.closeMenuBranch(parent.parentIndex);
    }
  };

  const classes = cls(
    ns.b(),
    ns.is('active', isActive),
    ns.is('disabled', disabled),
    className,
  );

  return (
    <li
      ref={ref}
      role="menuitem"
      tabIndex={disabled ? -1 : 0}
      aria-disabled={disabled || undefined}
      className={classes}
      style={style}
      onClick={handleClick}
      onKeyDown={(event) => {
        if (event.key === 'Enter' || event.key === ' ') {
          event.preventDefault();
          handleClick();
        }
      }}
      {...rest}
    >
      {icon && <span className={ns.e('icon')}>{icon}</span>}
      <span className={ns.e('title')}>{children}</span>
    </li>
  );
});

import { forwardRef, type HTMLAttributes, type ReactNode } from 'react';
import { cls, useNamespace } from '../../utils';

export interface MenuItemGroupProps extends Omit<HTMLAttributes<HTMLLIElement>, 'title'> {
  /** Group label. */
  title?: ReactNode;
  children?: ReactNode;
}

export const MenuItemGroup = forwardRef<HTMLLIElement, MenuItemGroupProps>(
  function MenuItemGroup(props, ref) {
    const { title, className, children, ...rest } = props;

    const ns = useNamespace('menu-item-group');

    return (
      <li ref={ref} className={cls(ns.b(), className)} role="presentation" {...rest}>
        {title !== undefined && title !== null && (
          <div className={ns.e('title')}>{title}</div>
        )}
        <ul className={ns.e('content')} role="group">
          {children}
        </ul>
      </li>
    );
  },
);

import {
  Children,
  forwardRef,
  type HTMLAttributes,
  isValidElement,
  type KeyboardEvent,
  type ReactNode,
  useEffect,
  useId,
  useMemo,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { Popper } from '../Overlay';
import { type SubMenuContextValue, SubMenuContext, useMenuContext, useSubMenuContext } from './Menu';
import { MenuItem } from './MenuItem';

export interface SubMenuProps extends Omit<HTMLAttributes<HTMLLIElement>, 'title'> {
  /** Unique identifier for the sub-menu. */
  index: string;
  /** Title rendered in the sub-menu trigger. */
  title?: ReactNode;
  /** Leading icon. */
  icon?: ReactNode;
  /** Disable interaction. */
  disabled?: boolean;
  children?: ReactNode;
}

function ChevronIcon() {
  return (
    <svg
      className="ec-sub-menu__arrow"
      viewBox="0 0 1024 1024"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
    >
      <path
        fill="currentColor"
        d="M831.872 340.864 512 652.672 192.128 340.864a30.592 30.592 0 0 0-42.752 0 29.12 29.12 0 0 0 0 41.6L489.664 714.24a32 32 0 0 0 44.672 0l340.288-331.776a29.12 29.12 0 0 0 0-41.6 30.592 30.592 0 0 0-42.752 0z"
      />
    </svg>
  );
}

/** Collect the `index` of every MenuItem descendant so the sub-menu can reflect active state. */
function collectItemIndices(children: ReactNode, indices: string[]): void {
  Children.forEach(children, (child) => {
    if (!isValidElement(child)) {
      return;
    }
    if (child.type === MenuItem) {
      const idx = (child.props as { index?: string }).index;
      if (idx) {
        indices.push(idx);
      }
      return;
    }
    const grandChildren = (child.props as { children?: ReactNode }).children;
    if (grandChildren) {
      collectItemIndices(grandChildren, indices);
    }
  });
}

export const SubMenu = forwardRef<HTMLLIElement, SubMenuProps>(function SubMenu(props, ref) {
  const { index, title, icon, disabled = false, className, style, children, ...rest } = props;

  const ns = useNamespace('sub-menu');
  const menu = useMenuContext();
  const parent = useSubMenuContext();
  const popupId = useId();

  const mode = menu?.mode ?? 'vertical';
  // `openedMenus` drives both vertical (inline) and horizontal (popup) open state,
  // so the popup is controlled and its expanded state is observable to context.
  const open = menu?.openedMenus.includes(index) ?? false;

  const childIndices: string[] = [];
  collectItemIndices(children, childIndices);
  const isActive = menu?.activeIndex ? childIndices.includes(menu.activeIndex) : false;

  // Register this sub-menu's parent path so `uniqueOpened` can preserve ancestors.
  const parentIndex = parent?.parentIndex ?? null;
  const registerSubMenu = menu?.registerSubMenu;
  const unregisterSubMenu = menu?.unregisterSubMenu;
  useEffect(() => {
    registerSubMenu?.(index, parentIndex);
    return () => unregisterSubMenu?.(index);
  }, [registerSubMenu, unregisterSubMenu, index, parentIndex]);

  // Expose this sub-menu as the parent path for its descendants.
  const subMenuContext = useMemo<SubMenuContextValue>(() => ({ parentIndex: index }), [index]);

  const handleTitleClick = () => {
    if (disabled) {
      return;
    }
    menu?.toggleMenu(index);
  };

  const handleTitleKeyDown = (event: KeyboardEvent<HTMLDivElement>) => {
    if (disabled) {
      return;
    }
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      menu?.toggleMenu(index);
    } else if (event.key === 'ArrowDown') {
      event.preventDefault();
      menu?.openMenu(index);
    } else if (event.key === 'Escape' && open) {
      event.preventDefault();
      menu?.closeMenu(index);
    }
  };

  const titleClasses = cls(
    ns.e('title'),
    ns.is('disabled', disabled),
  );

  const titleContent = (
    <>
      {icon && <span className={ns.e('icon')}>{icon}</span>}
      <span className={ns.e('label')}>{title}</span>
      <span className={cls(ns.e('arrow-wrap'), ns.is('opened', open))}>
        <ChevronIcon />
      </span>
    </>
  );

  // Horizontal mode renders the children in a Popper popup. The Popper is
  // controlled by the menu context so the trigger can open it via keyboard and
  // its expanded state stays in sync with `openedMenus`.
  if (mode === 'horizontal') {
    const reference = (
      <li
        ref={ref}
        className={cls(ns.b(), ns.is('opened', open), ns.is('active', isActive), ns.is('disabled', disabled), className)}
        style={style}
        {...rest}
      >
        <div
          className={titleClasses}
          role="menuitem"
          tabIndex={disabled ? -1 : 0}
          aria-haspopup="menu"
          aria-expanded={open}
          aria-controls={popupId}
          aria-disabled={disabled || undefined}
          onKeyDown={handleTitleKeyDown}
        >
          {titleContent}
        </div>
      </li>
    );

    return (
      <SubMenuContext.Provider value={subMenuContext}>
        <Popper
          reference={reference}
          open={open}
          onOpenChange={(next) => {
            if (disabled) {
              return;
            }
            if (next) {
              menu?.openMenu(index);
            } else {
              menu?.closeMenu(index);
            }
          }}
          trigger="hover"
          placement="bottom-start"
          offset={6}
          role="menu"
          disabled={disabled}
          popperClass="ec-menu__popper"
        >
          <ul id={popupId} className={ns.e('popup')} role="menu">
            {children}
          </ul>
        </Popper>
      </SubMenuContext.Provider>
    );
  }

  // Vertical mode expands and collapses inline.
  return (
    <li
      ref={ref}
      className={cls(ns.b(), ns.is('opened', open), ns.is('active', isActive), ns.is('disabled', disabled), className)}
      style={style}
      {...rest}
    >
      <div
        className={titleClasses}
        role="menuitem"
        tabIndex={disabled ? -1 : 0}
        aria-haspopup="menu"
        aria-expanded={open}
        aria-controls={popupId}
        aria-disabled={disabled || undefined}
        onClick={handleTitleClick}
        onKeyDown={handleTitleKeyDown}
      >
        {titleContent}
      </div>
      <ul
        id={popupId}
        role="menu"
        className={cls(ns.e('content'), ns.is('opened', open))}
      >
        <SubMenuContext.Provider value={subMenuContext}>{children}</SubMenuContext.Provider>
      </ul>
    </li>
  );
});

export * from './Menu';
export * from './MenuItem';
export * from './SubMenu';
export * from './MenuItemGroup';

.ec-menu {
  --ec-menu-item-height: 56px;
  --ec-menu-horizontal-item-height: 60px;
  --ec-menu-sub-item-height: 50px;
  --ec-menu-item-font-size: var(--ec-font-size-base);
  --ec-menu-padding-horizontal: 20px;
  --ec-menu-base-level-padding: 20px;
  --ec-menu-level-padding: 20px;
  --ec-menu-icon-width: 24px;
  --ec-menu-text-color: var(--ec-text-color-regular);
  --ec-menu-hover-text-color: var(--ec-text-color-primary);
  --ec-menu-active-color: var(--ec-color-primary);
  --ec-menu-disabled-color: var(--ec-disabled-text-color);
  --ec-menu-bg-color: var(--ec-fill-color-blank);
  --ec-menu-hover-bg-color: var(--ec-fill-color-light);
  --ec-menu-border-color: var(--ec-border-color-light);

  box-sizing: border-box;
  margin: 0;
  padding: 0;
  list-style: none;
  font-family: var(--ec-font-family);
  font-size: var(--ec-menu-item-font-size);
  background-color: var(--ec-menu-bg-color);
}

.ec-menu *,
.ec-menu *::before,
.ec-menu *::after {
  box-sizing: border-box;
}

/* ---- Vertical layout ---- */
.ec-menu--vertical {
  display: flex;
  flex-direction: column;
  border-right: var(--ec-border-width) var(--ec-border-style) var(--ec-menu-border-color);
}

.ec-menu--vertical.is-collapse {
  --ec-menu-padding-horizontal: 0;
  width: var(--ec-menu-item-height);
}

.ec-menu--vertical.is-collapse .ec-menu-item__title,
.ec-menu--vertical.is-collapse .ec-sub-menu__label,
.ec-menu--vertical.is-collapse .ec-sub-menu__arrow-wrap,
.ec-menu--vertical.is-collapse .ec-menu-item-group__title {
  display: none;
}

.ec-menu--vertical.is-collapse .ec-menu-item,
.ec-menu--vertical.is-collapse .ec-sub-menu__title {
  justify-content: center;
  padding-left: 0;
  padding-right: 0;
}

.ec-menu--vertical.is-collapse .ec-sub-menu__content {
  display: none;
}

/* ---- Horizontal layout ---- */
.ec-menu--horizontal {
  display: flex;
  flex-direction: row;
  align-items: center;
  border-bottom: var(--ec-border-width) var(--ec-border-style) var(--ec-menu-border-color);
}

.ec-menu--horizontal > .ec-menu-item,
.ec-menu--horizontal > .ec-sub-menu > .ec-sub-menu__title,
.ec-menu--horizontal > .ec-sub-menu {
  height: var(--ec-menu-horizontal-item-height);
}

.ec-menu--horizontal > .ec-menu-item,
.ec-menu--horizontal > .ec-sub-menu > .ec-sub-menu__title {
  border-bottom: 2px solid transparent;
}

.ec-menu--horizontal > .ec-menu-item.is-active,
.ec-menu--horizontal > .ec-sub-menu.is-active > .ec-sub-menu__title {
  color: var(--ec-menu-active-color);
  border-bottom-color: var(--ec-menu-active-color);
}

/* ---- Menu item ---- */
.ec-menu-item {
  display: flex;
  align-items: center;
  gap: 6px;
  box-sizing: border-box;
  height: var(--ec-menu-item-height);
  padding: 0 var(--ec-menu-padding-horizontal);
  margin: 0;
  font-size: var(--ec-menu-item-font-size);
  line-height: var(--ec-menu-item-height);
  white-space: nowrap;
  list-style: none;
  color: var(--ec-menu-text-color);
  cursor: pointer;
  outline: none;
  user-select: none;
  transition: var(--ec-transition-all);
}

.ec-menu-item:hover {
  color: var(--ec-menu-hover-text-color);
  background-color: var(--ec-menu-hover-bg-color);
}

.ec-menu-item:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: -2px;
}

.ec-menu-item.is-active {
  color: var(--ec-menu-active-color);
}

.ec-menu-item.is-disabled {
  color: var(--ec-menu-disabled-color);
  cursor: not-allowed;
  background: none;
  opacity: 0.75;
}

.ec-menu-item.is-disabled:hover {
  background: none;
  color: var(--ec-menu-disabled-color);
}

.ec-menu-item__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: var(--ec-menu-icon-width);
  font-size: 18px;
}

.ec-menu-item__title {
  display: inline-flex;
  align-items: center;
}

/* ---- Sub-menu ---- */
.ec-sub-menu {
  box-sizing: border-box;
  list-style: none;
  padding: 0;
  margin: 0;
}

.ec-sub-menu__title {
  display: flex;
  align-items: center;
  gap: 6px;
  box-sizing: border-box;
  height: var(--ec-menu-item-height);
  padding: 0 var(--ec-menu-padding-horizontal);
  font-size: var(--ec-menu-item-font-size);
  line-height: var(--ec-menu-item-height);
  white-space: nowrap;
  color: var(--ec-menu-text-color);
  cursor: pointer;
  outline: none;
  user-select: none;
  transition: var(--ec-transition-all);
}

.ec-sub-menu__title:hover {
  color: var(--ec-menu-hover-text-color);
  background-color: var(--ec-menu-hover-bg-color);
}

.ec-sub-menu__title:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: -2px;
}

.ec-sub-menu.is-active > .ec-sub-menu__title {
  color: var(--ec-menu-active-color);
}

.ec-sub-menu__title.is-disabled {
  color: var(--ec-menu-disabled-color);
  cursor: not-allowed;
  opacity: 0.75;
}

.ec-sub-menu__title.is-disabled:hover {
  background: none;
  color: var(--ec-menu-disabled-color);
}

.ec-sub-menu__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: var(--ec-menu-icon-width);
  font-size: 18px;
}

.ec-sub-menu__label {
  flex: 1;
  display: inline-flex;
  align-items: center;
}

.ec-sub-menu__arrow-wrap {
  display: inline-flex;
  align-items: center;
  margin-left: auto;
  transition: transform var(--ec-transition-duration);
}

.ec-sub-menu__arrow-wrap.is-opened {
  transform: rotate(180deg);
}

.ec-sub-menu__arrow {
  width: 14px;
  height: 14px;
}

/* ---- Inline (vertical) sub-menu content ---- */
.ec-sub-menu__content {
  margin: 0;
  padding: 0;
  list-style: none;
  overflow: hidden;
  max-height: 0;
  transition: max-height var(--ec-transition-duration) ease-in-out;
}

.ec-sub-menu__content.is-opened {
  max-height: 1000px;
}

/* Indentation for nested vertical items. */
.ec-menu--vertical .ec-sub-menu__content .ec-menu-item,
.ec-menu--vertical .ec-sub-menu__content .ec-sub-menu__title {
  height: var(--ec-menu-sub-item-height);
  line-height: var(--ec-menu-sub-item-height);
  padding-left: calc(var(--ec-menu-base-level-padding) + var(--ec-menu-level-padding));
  background-color: var(--ec-fill-color-lighter);
}

.ec-menu--vertical .ec-sub-menu__content .ec-sub-menu__content .ec-menu-item,
.ec-menu--vertical .ec-sub-menu__content .ec-sub-menu__content .ec-sub-menu__title {
  padding-left: calc(var(--ec-menu-base-level-padding) + var(--ec-menu-level-padding) * 2);
}

/* ---- Horizontal sub-menu popup (rendered through Popper) ---- */
.ec-menu__popper {
  padding: 5px 0;
  min-width: 200px;
  background-color: var(--ec-menu-bg-color);
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-border-color-light);
  border-radius: var(--ec-border-radius-base);
  box-shadow: var(--ec-box-shadow-light);
}

.ec-sub-menu__popup {
  margin: 0;
  padding: 0;
  list-style: none;
}

.ec-sub-menu__popup .ec-menu-item,
.ec-sub-menu__popup .ec-sub-menu__title {
  height: var(--ec-menu-sub-item-height);
  line-height: var(--ec-menu-sub-item-height);
}

/* ---- Menu item group ---- */
.ec-menu-item-group {
  box-sizing: border-box;
  list-style: none;
  padding: 0;
  margin: 0;
}

.ec-menu-item-group__title {
  padding: 8px 0 8px var(--ec-menu-padding-horizontal);
  font-size: var(--ec-font-size-small);
  line-height: 1;
  color: var(--ec-text-color-secondary);
}

.ec-menu-item-group__content {
  margin: 0;
  padding: 0;
  list-style: none;
}
